TITLE = '転勤・単身赴任 費用準備診断｜転勤先・家族構成から費用と準備リストを生成'
DESCRIPTION = '転勤先・家族構成から単身赴任のコストと準備リストを自動生成。8つの質問で年間追加コスト試算・準備チェックリスト・節約ポイントを提案する無料診断。'
JS_CODE = 'const answers = {};\n    const totalQ = 8;\n\n    document.querySelectorAll(\'.quiz-btn\').forEach(btn => {\n      btn.addEventListener(\'click\', function() {\n        const q = parseInt(this.dataset.q);\n        const v = this.dataset.v;\n        answers[q] = v;\n        document.querySelectorAll(`[data-q="${q}"]`).forEach(b => b.classList.remove(\'border-blue-500\',\'bg-blue-100\'));\n        this.classList.add(\'border-blue-500\',\'bg-blue-100\');\n        setTimeout(() => {\n          if (q < totalQ) {\n            document.getElementById(`q${q}`).classList.add(\'hidden\');\n            document.getElementById(`q${q+1}`).classList.remove(\'hidden\');\n            document.getElementById(\'progress-bar\').style.width = (q/totalQ*100)+\'%\';\n            document.getElementById(\'progress-text\').textContent = `質問 ${q+1} / ${totalQ}`;\n          } else { showResult(); }\n        }, 300);\n      });\n    });\n\n    function showResult() {\n      document.getElementById(\'quiz-section\').classList.add(\'hidden\');\n      document.getElementById(\'result-section\').classList.remove(\'hidden\');\n\n      const destination = answers[1];\n      const family = answers[2];\n      const costLevel = answers[3];\n      const companyHelp = answers[4];\n      const period = answers[5];\n      const homeTrip = answers[6];\n      const currentRent = parseInt(answers[7]) || 10;\n      const movingCover = answers[8];\n\n      // Base additional monthly cost\n      let monthlyAdd = 0;\n\n      // Housing additional cost\n      const destRent = { urban: 12, rural: 6, asia: 15, west: 25 };\n      const newRent = destRent[destination] || 10;\n      const soloRent = family === \'solo-family\' ? newRent : 0; // single unit needed\n      const homeRent = family === \'solo-family\' ? currentRent : 0; // keep home\n      monthlyAdd += soloRent;\n\n      // Living cost diff\n      const costAdd = { low: -2, same: 0, high: 3, \'much-high\': 8 };\n      monthlyAdd += costAdd[costLevel] || 0;\n\n      // Home trip cost\n      const tripMap = { weekly: 3, monthly: 1.5, few: 0.3, none: 0 };\n      const tripMonthly = tripMap[homeTrip] || 0;\n      monthlyAdd += tripMonthly;\n\n      // One-time moving cost\n      const movingTotal = 30; // avg\n      const movingCoverMap = { \'100\': 0, \'50\': 15, \'cap\': 15, \'0\': movingTotal };\n      const movingSelfPay = movingCoverMap[movingCover] || 15;\n\n      // Monthly total\n      const annualAdd = Math.round(monthlyAdd * 12 + movingSelfPay);\n\n      // Period total\n      const periodYears = { short: 1, mid: 2, long: 4, unknown: 3 };\n      const years = periodYears[period] || 2;\n      const totalAdd = annualAdd * years;\n\n      // Checklist\n      const checklist = [\n        \'✅ 転勤辞令・内示を書面で確認\',\n        \'✅ 会社の転勤規定・補助内容を人事に確認\',\n        \'✅ 引越し業者の見積もり（複数社比較）\',\n        \'✅ 転居先の物件探し・内見\',\n        \'✅ 住民票・免許証の住所変更手続き\',\n        \'✅ 郵便の転送設定（1年間）\',\n        \'✅ 公共料金（電気・ガス・水道）の引越し手続き\',\n        \'✅ 国民健康保険・年金の住所変更（必要な場合）\',\n      ];\n\n      if (family === \'solo-family\') {\n        checklist.push(\'✅ 家族の緊急連絡先・近隣サポート体制の確認\');\n        checklist.push(\'✅ 子どもの転校手続き（帯同の場合）\');\n        checklist.push(\'✅ 単身赴任手当・家族手当の継続確認\');\n      }\n\n      if (destination === \'asia\' || destination === \'west\') {\n        checklist.push(\'✅ パスポート・VISA手続き\');\n        checklist.push(\'✅ 海外赴任手当・海外保険の確認\');\n        checklist.push(\'✅ 現地の銀行口座開設準備\');\n        checklist.push(\'✅ 子どもの現地校・インターナショナルスクール確認\');\n      }\n\n      // Saving tips\n      const tips = [\n        \'📦 家具は転居先でリサイクルショップ・フリマ活用（運搬コスト削減）\',\n        \'🚊 帰省は新幹線より高速バス・LCCを活用\',\n        \'🍱 外食を減らし自炊習慣をつける（月2〜3万円節約）\',\n        \'📱 格安SIMに切り替える（月5,000円〜節約）\',\n        \'💡 単身向けのコンパクト家電・家具で光熱費削減\',\n      ];\n\n      if (homeTrip === \'weekly\') {\n        tips.push(\'🏠 週末帰宅は通勤定期の代わりに月額帰省手当を会社に確認\');\n      }\n\n      let html = `\n        <div class="bg-orange-50 border-2 border-orange-400 rounded-xl p-4 mb-4 text-center">\n          <p class="text-sm text-gray-500 mb-1">年間追加コスト試算</p>\n          <p class="text-4xl font-bold text-orange-600">${annualAdd}万円</p>\n          <p class="text-sm text-gray-500 mt-1">（初年度・引越し費用含む）</p>\n        </div>\n\n        <div '
